'use client'

import { Suspense, useEffect, useState, lazy } from 'react'
import { ProtectedRoute } from '@/src/components/ProtectedRoute'
import { MainLayout } from '@/src/components/MainLayout'
import { Outlet } from '@/src/types'
import { getStorageAdapter } from '@/src/services/storage'

// Lazy load the CreateOrderContent component with named export
const CreateOrderContent = lazy(() => 
  import('@/src/page-components/CreateOrderContent').then(module => ({ default: module.CreateOrderContent }))
)

function CreateOrderLoader() {
  return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="flex flex-col items-center gap-3">
        <div className="w-10 h-10 border-4 border-[#ED0577] border-t-transparent rounded-full animate-spin" />
        <p className="text-sm text-gray-600">Loading order creation...</p>
      </div>
    </div>
  )
}

function CreateOrderPageContent() {
  const [outlets, setOutlets] = useState<Outlet[]>([])
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    const loadOutlets = async () => {
      try {
        const adapter = getStorageAdapter()
        const loadedOutlets = await adapter.getOutlets()
        setOutlets(loadedOutlets)
      } catch (error) {
        console.error('Failed to load outlets:', error)
      } finally {
        setIsLoading(false)
      }
    }

    loadOutlets()
  }, [])

  return (
    <Suspense fallback={<CreateOrderLoader />}>
      <CreateOrderContent outlets={outlets} isLoading={isLoading} />
    </Suspense>
  )
}

export default function CreateOrderPage() {
  return (
    <ProtectedRoute>
      <MainLayout>
        <CreateOrderPageContent />
      </MainLayout>
    </ProtectedRoute>
  )
}
